import{H as e,R as t,U as n,V as r,W as i,j as a,nt as o,ot as s}from"./chunks/framework.B4R2P_rl.js";var c=JSON.parse(`{"title":"Preview channel","description":"How the preview channel ships upcoming Citizen features ahead of a stable release","frontmatter":{"title":"Preview channel","description":"How the preview channel ships upcoming Citizen features ahead of a stable release"},"headers":[],"relativePath":"contribute/preview-channel.md","filePath":"contribute/preview-channel.md","lastUpdated":1783556944000}`),l={name:`contribute/preview-channel.md`};function u(a,c,l,u,d,f){let p=s(`CopyOrDownloadAsMarkdownButtons`);return o(),r(`div`,null,[c[0]||=t(`div`,{style:{display:`none`},hidden:`true`,"aria-hidden":`true`,"data-nosnippet":``},`Are you an LLM? You can read better optimized documentation at /mediawiki-skins-Citizen/contribute/preview-channel.md for this page in Markdown format`,-1),c[1]||=t(`h1`,{id:`preview-channel`,tabindex:`-1`},[n(`Preview channel `),t(`a`,{class:`header-anchor`,href:`#preview-channel`,"aria-label":`Permalink to “Preview channel”`},`​`)],-1),i(p),c[2]||=e(`<p>The <strong>preview channel</strong> lets you safely test upcoming Citizen features before they reach a stable release. A feature is gated behind the channel only when it has to be — for one of two reasons:</p><ul><li><strong>A breaking change</strong> — it must wait for the next major.</li><li><strong>Still experimental</strong> — it isn&#39;t ready to ship yet.</li></ul><p>Anything that works in both worlds ships normally, never gated.</p><div class="info custom-block"><p class="custom-block-title">Release policy</p><p>Citizen introduces breaking changes only in major versions, and a new major ships only alongside a MediaWiki LTS release (roughly every two years). The preview channel lets that work land on <code>main</code> early instead of waiting for the major.</p></div><h2 id="opting-in" tabindex="-1">Opting in <a class="header-anchor" href="#opting-in" aria-label="Permalink to “Opting in”">​</a></h2><p>Turn the preview on for your browser, or for the whole wiki.</p><p><strong>Per browser</strong> — append <code>?citizenpreview=4</code> to any page URL. The choice persists in a 24-hour cookie for your browser only; readers are unaffected. Append <code>?citizenpreview=0</code> to switch back.</p><p><strong>Wiki-wide</strong> — set <a href="./../config/#wgcitizenpreview"><code>$wgCitizenPreview</code></a>:</p><div class="vp-code-block-title"><div class="vp-code-block-title-bar"><span class="vp-code-block-title-text" data-title="LocalSettings.php">LocalSettings.php</span></div><div class="language-php"><button title="Copy Code" class="copy"></button><span class="lang">php</span><pre class="shiki shiki-themes github-light github-dark" style="--shiki-light:#24292e;--shiki-dark:#e1e4e8;--shiki-light-bg:#fff;--shiki-dark-bg:#24292e;" tabindex="0" dir="ltr"><code><span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">$wgCitizenPreview </span><span style="--shiki-light:#c62739;--shiki-dark:#F97583;">=</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> 4</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">;</span></span></code></pre></div></div><p>Only the value <code>4</code> activates the preview during this cycle; <code>0</code> or any other value keeps the stable experience. The URL parameter and cookie take precedence over the config, so a browser can opt in or out regardless of the wiki default.</p><p>Preview requests carry the <code>citizen-v4</code> class on <code>&lt;html&gt;</code>, and it stays there for the whole Citizen 4 release. For what changes and how to migrate your customizations, see the <a href="./../guide/migrating-to-citizen-4">Migrating to Citizen 4 guide</a>.</p><h2 id="gating-a-feature" tabindex="-1">Gating a feature <a class="header-anchor" href="#gating-a-feature" aria-label="Permalink to “Gating a feature”">​</a></h2><p>Gate preview-only code on the <code>citizen-v4</code> class. It is present exactly when the preview is active, and it travels with the HTML the page was served with — even from an edge cache — so gate on the class, never on &quot;did the module load.&quot;</p><table tabindex="0"><thead><tr><th style="text-align:left;">Surface</th><th style="text-align:left;">Convention</th></tr></thead><tbody><tr><td style="text-align:left;">CSS, large surface</td><td style="text-align:left;">Separate ResourceLoader module; the hook loads exactly one per request (the token-module pattern). Use this for whole-stylesheet surfaces; when in doubt, start with a co-located guard block and promote if it grows.</td></tr><tr><td style="text-align:left;">CSS, small delta</td><td style="text-align:left;">Co-located <code>:root.citizen-v4 &amp;</code> block in the component&#39;s LESS file.</td></tr><tr><td style="text-align:left;">Extension <code>skinStyles/</code></td><td style="text-align:left;">Guard-block only — skinStyles attach to the extension&#39;s modules and cannot be swapped per-request.</td></tr><tr><td style="text-align:left;">PHP</td><td style="text-align:left;">Consume the resolved value from <code>PreviewChannel::isPreview()</code>; never re-read the config, cookie, or URL elsewhere.</td></tr><tr><td style="text-align:left;">Mustache / markup</td><td style="text-align:left;">Prefer additive markup both worlds can style. Genuine forks use an <code>is-v4</code> template-data boolean. Markup forks are the rarest gate — each is a cache-window hazard.</td></tr><tr><td style="text-align:left;">JS</td><td style="text-align:left;"><code>document.documentElement.classList.contains( &#39;citizen-v4&#39; )</code>.</td></tr></tbody></table><p>Legacy-side code that the next major will delete gets a <code>// citizen-v4-remove</code> comment, so the eventual cleanup is a grep.</p><p>When you gate a feature:</p><ul><li>Ship it production-quality — it reaches early-adopter wikis through ordinary minor releases, even though its shape may still evolve.</li><li>Give user-facing changelog entries a &quot;(preview)&quot; suffix, so wikis can tell what does and doesn&#39;t affect them.</li><li>Make preview-only config and preference options degrade gracefully under stable: documented fallback, hidden UI.</li><li>Open a preview-only feature&#39;s docs page with a <code>::: warning Preview (Citizen 4)</code> note stating it becomes the default in 4.0.</li><li>Cover both sides wherever behavior forks — Vitest toggles the class on the fixture root; PHPUnit passes both resolved values.</li></ul>`,17)])}var d=a(l,[[`render`,u]]);export{c as __pageData,d as default};